import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { getAllDoctors, deleteDoctor } from '../services/api';
import { useAuth } from '../context/AuthContext';
import Navbar from '../components/Navbar';

const SPECS = ['All', 'Cardiology', 'Neurology', 'Orthopedics', 'Dermatology', 'Pediatrics', 'General Medicine'];

const specColors = {
  Cardiology:       { bg: '#fef2f2', color: '#dc2626', icon: '🫀' },
  Neurology:        { bg: '#f0fdf4', color: '#16a34a', icon: '🧠' },
  Orthopedics:      { bg: '#fff7ed', color: '#ea580c', icon: '🦴' },
  Dermatology:      { bg: '#fdf4ff', color: '#a21caf', icon: '✨' },
  Pediatrics:       { bg: '#eff6ff', color: '#2563eb', icon: '👶' },
  'General Medicine':{ bg: '#f0fdfa', color: '#0d9488', icon: '🩺' },
};

const Doctors = () => {
  const { user } = useAuth();
  const navigate  = useNavigate();
  const [doctors,  setDoctors]  = useState([]);
  const [search,   setSearch]   = useState('');
  const [specFilter, setSpecFilter] = useState('All');
  const [loading,  setLoading]  = useState(true);

  const fetchDoctors = async () => {
    try {
      const { data } = await getAllDoctors();
      setDoctors(data);
    } catch (e) { console.log(e); }
    finally { setLoading(false); }
  };

  useEffect(() => { fetchDoctors(); }, []);

  const handleDelete = async (id) => {
    if (!window.confirm('Remove this doctor from the system?')) return;
    try {
      await deleteDoctor(id);
      fetchDoctors();
    } catch (e) {
      alert(e.response?.data?.message || 'Delete failed');
    }
  };

  const filtered = doctors.filter(d => {
    const name = d.userId?.name?.toLowerCase() || '';
    const spec = d.specialization?.toLowerCase() || '';
    const q    = search.toLowerCase();
    return (specFilter === 'All' || d.specialization === specFilter) &&
           (!q || name.includes(q) || spec.includes(q));
  });

  return (
    <div style={S.page}>
      <div style={S.overlay}></div>

      <Navbar />

      <div style={S.wrap}>

        {/* Header */}
        <div style={S.header}>
          <div>
            <h1 style={S.title}>Our Specialists</h1>
            <p style={S.subtitle}>Browse and connect with our verified medical professionals</p>
          </div>
        </div>

        {/* Filters */}
        <div style={S.filters}>
          <input
            style={S.searchInput}
            placeholder="🔍 Search by name or specialization"
            value={search}
            onChange={e => setSearch(e.target.value)}
          />

          <div style={S.specPills}>
            {SPECS.map(s => (
              <button
                key={s}
                style={{ ...S.pill, ...(specFilter === s ? S.pillActive : {}) }}
                onClick={() => setSpecFilter(s)}
              >
                {s}
              </button>
            ))}
          </div>
        </div>

        {/* Doctor Grid */}
        {loading ? (
          <div style={S.loadingWrap}>Loading...</div>
        ) : filtered.length === 0 ? (
          <div style={S.empty}>No doctors found</div>
        ) : (
          <div style={S.grid}>
            {filtered.map(d => {
              const sc = specColors[d.specialization] || { bg: '#f8fafc', color: '#6366f1', icon: '🩺' };

              return (
                <div key={d._id} style={S.card}>

                  <div style={{ ...S.cardTop, background: sc.bg }}>
                    <div style={{ ...S.avatar, background: sc.bg, color: sc.color }}>
                      {sc.icon}
                    </div>
                    <div style={{ ...S.specBadge, color: sc.color }}>
                      {d.specialization}
                    </div>
                  </div>

                  <div style={S.cardBody}>
                    <h3 style={S.docName}>{d.userId?.name}</h3>
                    <p style={S.qual}>{d.qualification}</p>

                    <div style={S.docMeta}>
                      <div>🎓 {d.experience} yrs</div>
                      <div>⭐ {d.rating}</div>
                    </div>

                    <div style={S.cardFoot}>
                      <div>
                        <div style={S.feeLabel}>Fee</div>
                        <div style={S.fee}>₹{d.consultationFee}</div>
                      </div>

                      <div style={S.cardBtns}>
                        {user?.role === 'patient' && (
                          <button style={S.bookBtn} onClick={() => navigate('/book')}>
                            Book
                          </button>
                        )}

                        {user?.role === 'admin' && (
                          <button style={S.delBtn} onClick={() => handleDelete(d._id)}>
                            Remove
                          </button>
                        )}
                      </div>
                    </div>
                  </div>

                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

const S = {
  page: {
    minHeight: '100vh',
    backgroundImage: 'url("images/hospital.png")',
    backgroundSize: 'cover',
    backgroundPosition: 'center',
    position: 'relative'
  },

  overlay: {
    position: 'absolute',
    width: '100%',
    height: '100%',
    background: 'rgba(255,255,255,0.85)'
  },

  wrap: {
    position: 'relative',
    zIndex: 1,
    padding: 20
  },

  header: { marginBottom: 20 },
  title: { fontSize: 28, fontWeight: 'bold' },
  subtitle: { color: '#555' },

  filters: { marginBottom: 20 },
  searchInput: { padding: 10, width: '100%', marginBottom: 10 },

  specPills: { display: 'flex', gap: 10 },
  pill: { padding: 6, border: '1px solid #ccc', borderRadius: 20 },
  pillActive: { background: '#6366f1', color: '#fff' },

  grid: { display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 20 },

  card: { background: '#fff', padding: 15, borderRadius: 10 },
  cardTop: { display: 'flex', justifyContent: 'space-between' },

  avatar: { padding: 10, borderRadius: 10 },
  specBadge: { fontSize: 12 },

  cardBody: {},
  docName: { fontWeight: 'bold' },
  qual: { color: '#666' },

  docMeta: { marginTop: 10 },

  cardFoot: { display: 'flex', justifyContent: 'space-between', marginTop: 10 },

  feeLabel: { fontSize: 12 },
  fee: { fontWeight: 'bold' },

  cardBtns: { display: 'flex', gap: 10 },

  bookBtn: {
    background: '#6366f1',
    color: '#fff',
    border: 'none',
    padding: '5px 10px'
  },

  delBtn: {
    border: '1px solid red',
    color: 'red',
    padding: '5px 10px'
  },

  loadingWrap: { textAlign: 'center' },
  empty: { textAlign: 'center' }
};

export default Doctors;
